select count(*) from postgres.posts as p, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v, postgres.badges as b, postgres.users as u where p.id = pl.relatedpostid and u.id = p.owneruserid and u.id = b.userid and u.id = ph.userid and u.id = v.userid and p.commentcount>=0 and p.commentcount<=13 and ph.posthistorytypeid=5 and ph.creationdate<=timestamp '2014-08-13 09:20:10' and v.creationdate>=timestamp '2010-07-19 00:00:00' and b."date"<=timestamp '2014-09-09 10:24:35' and u.views>=0 and u.downvotes>=0 and u.creationdate>=timestamp '2010-08-04 16:59:53' and u.creationdate<=timestamp '2014-07-22 15:15:22';
